// Accept Retell's { call, args } envelope (webhook wraps it under .body),
// and also a flat body. Build the record + a booking reference.
const root = $input.first().json.body || $input.first().json;
const args = root.args || root;
const call = root.call || {};

function makeRef() {
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
  let s = '';
  for (let i = 0; i < 4; i++) s += chars[Math.floor(Math.random() * chars.length)];
  return 'QDC-' + s;
}

const required = ['patient_name', 'phone_number', 'service', 'preferred_datetime'];
const missing = required.filter((k) => !String(args[k] || '').trim());

const record = {
  timestamp: new Date().toISOString(),
  booking_reference: makeRef(),
  patient_name: String(args.patient_name || '').trim(),
  phone_number: String(args.phone_number || '').trim(),
  patient_email: String(args.patient_email || '').trim(),
  service: String(args.service || '').trim(),
  preferred_datetime: String(args.preferred_datetime || '').trim(),
  confirmed_datetime: String(args.preferred_datetime || '').trim(),
  notes: String(args.notes || '').trim(),
  call_id: String(call.call_id || ''),
  status: missing.length ? 'failed' : 'confirmed',
  missing: missing.join(', ')
};

return [{ json: record }];
